create extension if not exists pgcrypto;
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end $$;

create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, display_name text not null default '', avatar_url text, height_cm numeric(5,1), current_weight_kg numeric(6,2), target_weight_kg numeric(6,2), training_goal text not null default 'Allgemeine Fitness', experience_level text not null default 'Anfänger', training_days_per_week smallint not null default 3 check (training_days_per_week between 1 and 7), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.exercises (id uuid primary key default gen_random_uuid(), user_id uuid references auth.users(id) on delete cascade, name text not null, muscle_group text not null, equipment_type text not null, exercise_type text not null default 'Kraft', description text, instructions text[] not null default '{}', image_url text, is_public boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint public_exercise_owner check (not is_public or user_id is null));
create table public.workout_plans (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, muscle_groups text[] not null default '{}', estimated_minutes integer not null default 45 check (estimated_minutes between 5 and 600), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.workout_plan_exercises (id uuid primary key default gen_random_uuid(), plan_id uuid not null references public.workout_plans(id) on delete cascade, exercise_id uuid not null references public.exercises(id) on delete restrict, sort_order integer not null default 0, sets integer not null check (sets > 0), reps integer not null check (reps > 0), weight_kg numeric(7,2) not null default 0, rest_seconds integer not null default 60 check (rest_seconds >= 0), created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(plan_id,sort_order));
create table public.workout_sessions (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, plan_id uuid references public.workout_plans(id) on delete set null, plan_name text not null, status text not null default 'active' check(status in ('active','completed','abandoned')), started_at timestamptz not null default now(), completed_at timestamptz, duration_seconds integer not null default 0, total_volume_kg numeric(12,2) not null default 0, current_exercise_index integer not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.workout_sets (id uuid primary key default gen_random_uuid(), session_id uuid not null references public.workout_sessions(id) on delete cascade, exercise_id uuid not null references public.exercises(id) on delete restrict, set_number integer not null, planned_reps integer not null default 0, actual_reps integer not null default 0, weight_kg numeric(7,2) not null default 0, completed boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(session_id,exercise_id,set_number));
create table public.body_measurements (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, measured_at timestamptz not null default now(), weight_kg numeric(6,2) not null check(weight_kg > 0), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.nutrition_goals (id uuid primary key default gen_random_uuid(), user_id uuid not null unique references auth.users(id) on delete cascade, calories integer not null default 2000, protein_g integer not null default 150, carbs_g integer not null default 220, fat_g integer not null default 70, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.meals (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, name text not null, eaten_at timestamptz not null default now(), calories integer not null default 0, protein_g numeric(7,2) not null default 0, carbs_g numeric(7,2) not null default 0, fat_g numeric(7,2) not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.meal_entries (id uuid primary key default gen_random_uuid(), meal_id uuid not null references public.meals(id) on delete cascade, name text not null, amount_g numeric(8,2) not null default 0, calories integer not null default 0, protein_g numeric(7,2) not null default 0, carbs_g numeric(7,2) not null default 0, fat_g numeric(7,2) not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.personal_records (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, exercise_id uuid references public.exercises(id) on delete set null, exercise_name text not null, weight_kg numeric(7,2) not null, achieved_at timestamptz not null default now(), created_at timestamptz not null default now(), updated_at timestamptz not null default now());

