create index exercises_user_idx on public.exercises(user_id); create index exercises_filter_idx on public.exercises(muscle_group,equipment_type); create index plans_user_idx on public.workout_plans(user_id,updated_at desc); create index plan_exercises_plan_idx on public.workout_plan_exercises(plan_id,sort_order); create index sessions_user_date_idx on public.workout_sessions(user_id,started_at desc); create index sets_session_idx on public.workout_sets(session_id); create index measurements_user_date_idx on public.body_measurements(user_id,measured_at); create index meals_user_date_idx on public.meals(user_id,eaten_at desc); create index records_user_date_idx on public.personal_records(user_id,achieved_at desc);

do $$ declare t text; begin foreach t in array array['profiles','exercises','workout_plans','workout_plan_exercises','workout_sessions','workout_sets','body_measurements','nutrition_goals','meals','meal_entries','personal_records'] loop execute format('alter table public.%I enable row level security',t); end loop; end $$;
create policy "profiles own" on public.profiles for all using(id=auth.uid()) with check(id=auth.uid());
create policy "exercises read public or own" on public.exercises for select using(is_public or user_id=auth.uid());
create policy "exercises write own" on public.exercises for all using(user_id=auth.uid() and not is_public) with check(user_id=auth.uid() and not is_public);
create policy "plans own" on public.workout_plans for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "plan exercises through owner" on public.workout_plan_exercises for all using(exists(select 1 from public.workout_plans p where p.id=plan_id and p.user_id=auth.uid())) with check(exists(select 1 from public.workout_plans p where p.id=plan_id and p.user_id=auth.uid()));
create policy "sessions own" on public.workout_sessions for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "sets through owner" on public.workout_sets for all using(exists(select 1 from public.workout_sessions s where s.id=session_id and s.user_id=auth.uid())) with check(exists(select 1 from public.workout_sessions s where s.id=session_id and s.user_id=auth.uid()));
create policy "measurements own" on public.body_measurements for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "nutrition goals own" on public.nutrition_goals for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "meals own" on public.meals for all using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy "meal entries through owner" on public.meal_entries for all using(exists(select 1 from public.meals m where m.id=meal_id and m.user_id=auth.uid())) with check(exists(select 1 from public.meals m where m.id=meal_id and m.user_id=auth.uid()));
create policy "records own" on public.personal_records for all using(user_id=auth.uid()) with check(user_id=auth.uid());

do $$ declare t text; begin foreach t in array array['profiles','exercises','workout_plans','workout_plan_exercises','workout_sessions','workout_sets','body_measurements','nutrition_goals','meals','meal_entries','personal_records'] loop execute format('create trigger set_%I_updated_at before update on public.%I for each row execute function public.set_updated_at()',t,t); end loop; end $$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,display_name) values(new.id,coalesce(new.raw_user_meta_data->>'display_name','')); insert into public.nutrition_goals(user_id) values(new.id); return new; end $$;
create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
create or replace function public.delete_current_user() returns void language plpgsql security definer set search_path=public as $$ begin delete from auth.users where id=auth.uid(); end $$;
revoke all on function public.delete_current_user() from public; grant execute on function public.delete_current_user() to authenticated;
